script:
frappe.ui.form.on('DPDP Assessment', {
    refresh(frm) {

        // ── Regenerate PDF ──────────────────────────────────────
        frm.add_custom_button('Regenerate PDF', function() {
            frappe.confirm(
                'Regenerate and re-email the PDF using stored AI content?',
                function() {
                    frappe.call({
                        method: 'dpdp_tool.api.generate_and_attach_pdf',
                        args: { docname: frm.doc.name },
                        callback: function() {
                            frappe.show_alert({ message: 'PDF generation started — reloading in 30s.', indicator: 'blue' });
                            setTimeout(() => frm.reload_doc(), 30000);
                        }
                    });
                }
            );
        }, 'Actions');

        // ── Re-run AI Calls ─────────────────────────────────────
        frm.add_custom_button('Re-run AI Analysis', function() {
            frappe.confirm(
                'Re-run both AI calls (summary and roadmap) and regenerate the PDF? This will overwrite existing AI content.',
                function() {
                    frappe.call({
                        method: 'dpdp_tool.api.run_summary_call',
                        args: { docname: frm.doc.name },
                        callback: function() {
                            frappe.show_alert({ message: 'Summary call started.', indicator: 'blue' });
                        }
                    });
                    frappe.call({
                        method: 'dpdp_tool.api.run_roadmap_call',
                        args: { docname: frm.doc.name },
                        callback: function() {
                            frappe.show_alert({ message: 'Roadmap call started — PDF will regenerate and email when complete. Reloading in 90s.', indicator: 'blue' });
                            setTimeout(() => frm.reload_doc(), 90000);
                        }
                    });
                }
            );
        }, 'Actions');

    }
});
